/* Group Coaching Icon */
.PageList li:nth-child(6) a::before {
  background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="white"><path d="M16 11c1.66 0 2.99-1.34 2.99-3S17.66 5 16 5s-3 1.34-3 3 1.34 3 3 3zm-8 0c1.66 0 2.99-1.34 2.99-3S9.66 5 8 5C6.34 5 5 6.34 5 8s1.34 3 3 3zm0 2c-2.33 0-7 1.17-7 3.5V19h14v-2.5c0-2.33-4.67-3.5-7-3.5zm8 0c-.29 0-.62.02-.97.05 1.16.84 1.97 1.97 1.97 3.45V19h6v-2.5c0-2.33-4.67-3.5-7-3.5z"/></svg>');
}

/* Workshops & Events Icon */
.PageList li:nth-child(7) a::before {
  background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="white"><path d="M19 3h-1V1h-2v2H8V1H6v2H5c-1.11 0-1.99.9-1.99 2L3 19c0 1.1.89 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm0 16H5V8h14v11z"/></svg>');
}

/* Resources Icon */
.PageList li:nth-child(8) a::before {
  background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="white"><path d="M19 2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h4l3 3 3-3h4c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z"/></svg>');
}

/* Success Stories Icon */
.PageList li:nth-child(9) a::before {
  background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="white"><path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2l-2.81 6.63L2 9.24l5.46 4.73L5.82 21z"/></svg>');
}

/* Blog & Insights Icon */
.PageList li:nth-child(10) a::before {
  background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="white"><path d="M19 2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h4l3 3 3-3h4c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z"/></svg>');
}

/* Contact Us Icon */
.PageList li:nth-child(11) a::before {
  background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="white"><path d="M16.6915026,12.4744748 L3.50612381,13.2599618 C3.19218622,13.2599618 3.03521743,13.4170592 3.03521743,13.5741566 L1.15159189,20.0151496 C0.8376543,20.8006365 0.99,21.89 1.77946707,22.52 C2.41,22.99 3.50612381,23.1 4.13399899,22.8429026 L21.714504,14.0454487 C22.6563168,13.5741566 23.1272231,12.6315722 22.9702544,11.6889879 L4.13399899,1.16700512 C3.34915502,0.9099075 2.40734225,0.9099075 1.77946707,1.44161685 C0.994623095,2.10604706 0.837654326,3.0486314 1.15159189,3.99701575 L3.03521743,10.4379088 C3.03521743,10.5950061 3.19218622,10.7521035 3.50612381,10.7521035 L16.6915026,11.5375905 C16.6915026,11.5375905 17.1624089,11.5375905 17.1624089,12.0088826 C17.1624089,12.4744748 16.6915026,12.4744748 16.6915026,12.4744748 Z"/></svg>');
}

/* Arrow indicators for expandable items */
.PageList a::after {
  content: '›';
  display: none;
  margin-left: auto;
  font-size: 20px;
  color: rgba(255, 255, 255, 0.7);
}

.PageList li:not(:first-child) a::after {
  display: inline-block;
}

/* Book a Session Button */
.PageList .book-session-btn {
  background: linear-gradient(135deg, #89c9ad 0%, #6db896 100%);
  color: #0d3333 !important;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-top: 20px;
  border-radius: 25px;
  padding: 16px 24px !important;
  text-align: center;
  display: flex;
  align-items: center;
  justify-content: center;
}

.PageList .book-session-btn::before {
  content: '📅';
  margin-right: 12px;
  font-size: 18px;
}

.PageList .book-session-btn::after {
  content: '→';
  margin-left: 12px;
  font-size: 18px;
}

.PageList .book-session-btn:hover {
  background: linear-gradient(135deg, #7db899 0%, #5ca687 100%);
  transform: translateY(-2px);
  box-shadow: 0 6px 16px rgba(137, 201, 173, 0.3);
}

/* Social Media Footer */
.PageList .social-footer {
  display: flex;
  justify-content: center;
  gap: 16px;
  margin-top: 30px;
  padding-top: 20px;
  border-top: 1px solid rgba(255, 255, 255, 0.2);
}

.PageList .social-icon {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background-color: rgba(137, 201, 173, 0.2);
  border: 1px solid rgba(137, 201, 173, 0.4);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #89c9ad;
  text-decoration: none;
  transition: all 0.3s ease;
  font-size: 18px;
}

.PageList .social-icon:hover {
  background-color: rgba(137, 201, 173, 0.4);
  transform: scale(1.1);
}

/* Responsive Design */
@media (max-width: 768px) {
  .PageList {
    padding: 15px 10px;
  }

  .PageList ul {
    gap: 8px;
  }

  .PageList a {
    padding: 12px 16px;
    font-size: 15px;
  }

  .PageList a::before {
    width: 20px;
    height: 20px;
    margin-right: 12px;
  }
}

/* Standard Blogger Styles */
body{
overflow-wrap:break-word;
word-break:break-word;
word-wrap:break-word
}
.hidden{
display:none
}
.invisible{
visibility:hidden
}
.container::after,.float-container::after{
clear:both;
content:"";
display:table
}
.clearboth{
clear:both
}
#comments .comment .comment-actions,.subscribe-popup .FollowByEmail .follow-by-email-submit,.widget.Profile .profile-link,.widget.Profile .profile-link.visit-profile{
background:0 0;
border:0;
box-shadow:none;
color:$(body.link.color);
cursor:pointer;
font-size:14px;
font-weight:700;
outline:0;
text-decoration:none;
text-transform:uppercase;
width:auto
}
.dim-overlay{
background-color:rgba(0,0,0,.54);
height:100vh;
left:0;
position:fixed;
top:0;
width:100%
}
#sharing-dim-overlay{
background-color:transparent
}
